pattern-printing.template:
for (int i = 1; i <= n; i++) {
    // leading spaces (if centered)
    for (int s = 1; s <= f(i); s++) System.out.print(' ');
    // content
    for (int c = 1; c <= g(i); c++) System.out.print('*');
    System.out.println();
}

digit-extraction.template:
while (n > 0) {
    int d = n % 10;   // process digit d
    n /= 10;
}

euclidean-gcd.template:
while (b != 0) {
    int t = b;
    b = a % b;
    a = t;
}
// a is gcd(a, b)

recursion-basics.template:
returnType fn(params) {
    if (baseCondition) return baseResult;
    // do some work, call fn on smaller input, combine
    return combine(work, fn(smaller));
}

two-pointers.template:
int l = 0, r = n - 1;
while (l < r) {
    // decide based on a[l] and a[r]
    if (cond) l++;
    else r--;
}

two-pointers.writeScanVariant:
int i = 0;
for (int j = 0; j < n; j++) {
    if (keep(a[j])) { a[i++] = a[j]; }
}

xor-trick.template:
int x = 0;
for (int v : a) x ^= v;
// x is the lonely element

linear-scan.template:
int best = initial;
for (int x : a) {
    // update state based on x
    best = better(best, x);
}

memoization.template:
Long[] memo = new Long[n + 1];
long solve(int x) {
    if (base(x)) return baseValue(x);
    if (memo[x] != null) return memo[x];
    return memo[x] = combine(solve(...), solve(...));
}

